import base64, os

# Create directory
os.makedirs('/user/current', exist_ok=True)

# The base64-encoded sketch.py content
encoded_code = """"""

# Decode and write to file
code = base64.b64decode(encoded_code).decode('utf-8')
with open('/user/current/sketch.py', 'w') as f:
    f.write(code)

print('✓ sketch.py deployed successfully!')
print(f'Wrote {len(code)} bytes to /user/current/sketch.py')
